#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e7 + 5;

char to(char c)
{
    if(c == '1') return '0';
    if(c == '0') return '1';
    return c;
}

int d[N], a[N];

signed main() {
    string inp, s;
    int n, tot = 1;
    cin >> n;
	cin >> inp;
    s = "$#";
	for(int i = 0; i < n; ++i)
    {
        s.push_back(inp[i]);
        s.push_back('#');
        tot += 2;
    }
	int pos = 1, mx = 1; 
    int ans = 0;
    a['1'] = '0', a['0'] = '1', a['#'] = '#';
	for(int i = 1; i <= tot; i += 1) {
        if(s[i] != '#') continue;
		d[i] = (i < mx ? min(mx - i, d[(pos << 1) - i]) : 1);
		while(i - d[i] > 0 && i + d[i] <= tot && s[i + d[i]] == a[s[i - d[i]]]) d[i]++;
		if(d[i] + i > mx) {
			mx = d[i] + i;
            pos = i;
		}
		ans += d[i] >> 1;
	}
	cout << ans;
	return 0;
}
